```class Solution {
public:
    int findBestValue(vector<int>& arr, int target) {
        int best_value = arr[0];
        int sum_diff = INT_MAX;

        for (int i = 1; i < arr.size(); i++) {
            int diff = abs(target - arr[i]);
            if (diff < sum_diff) {
                best_value = arr[i];
                sum_diff = diff;
            }
        }

        return best_value;
    }
};
```

